import{c as l,$ as h,Q as i,j as c,m as a,h as r,ax as t,n as s,o as d,S as n}from"./chunks/framework.D-SAPBj4.js";const w=JSON.parse('{"title":"How it evolves","description":"","frontmatter":{"title":"How it evolves","outline":[2,3]},"headers":[],"relativePath":"how-it-evolves.md","filePath":"how-it-evolves.md","lastUpdated":1783005764000}'),u={name:"how-it-evolves.md"};function p(g,e,f,m,b,v){const o=h("Mermaid");return i(),c("div",null,[e[3]||(e[3]=a('<h1 id="how-it-evolves" tabindex="-1">How it evolves <a class="header-anchor" href="#how-it-evolves" aria-label="Permalink to &quot;How it evolves&quot;">​</a></h1><p>NLPM is 9 weeks old. The first commit landed on 2026-03-25; the current release is <strong>v1.0.0</strong> — the multi-tool branded release that expanded NLPM from Claude-Code-only to Claude Code + Codex CLI + Antigravity, splitting <code>nlpm:conventions</code> into a universal floor plus three per-tool overlays. In between: 1,300+ commits and six minor-version gates (v0.2 → v0.4 → v0.6 → v0.7 → v0.8 → v1.0). The cadence is high because the rules keep getting proven wrong — or right in ways the rulebook didn&#39;t yet encode — by contact with real repositories.</p><p>This page describes the mechanism that absorbs that contact and turns it into rulebook changes. It is the closest thing NLPM has to a thesis: a rulebook that doesn&#39;t get updated by evidence isn&#39;t a rulebook, it&#39;s an opinion.</p><h2 id="the-premise" tabindex="-1">The premise <a class="header-anchor" href="#the-premise" aria-label="Permalink to &quot;The premise&quot;">​</a></h2><p>Most static analysis tools ship a rulebook and freeze it. The rules are an asset; updating them costs review time; updating them too aggressively is how false positives accumulate. So the rules settle.</p><p>NL artifacts don&#39;t allow that. The spec moves (Anthropic published Agent Skills on 2025-12-18; the Linux Foundation forked it; OpenAI, Microsoft, and Google each adopted on different timelines with different defaults). The community vocabulary keeps shifting (today&#39;s &quot;command&quot; is yesterday&#39;s &quot;task&quot;). The maintainers in the corpus push back — sometimes the pushback is &quot;your rule found a real bug, thanks&quot;, sometimes it&#39;s &quot;your rule doesn&#39;t apply to my repo and here&#39;s why&quot;. Either signal updates the rulebook.</p><p>NLPM treats every rule as a hypothesis with a half-life. The auditor pipeline is the mechanism that measures the half-life empirically and opens a PR when the evidence demands one.</p><h2 id="the-loop-end-to-end" tabindex="-1">The loop, end-to-end <a class="header-anchor" href="#the-loop-end-to-end" aria-label="Permalink to &quot;The loop, end-to-end&quot;">​</a></h2>',8)),(i(),r(n,null,{default:t(()=>[d(o,{id:"mermaid-24",class:"mermaid-diagram",graph:"flowchart%20TD%0A%20%20Discover%5Bauditor-discover%5D%20--%3E%20Audit%5Bauditor-audit%5D%0A%20%20Audit%20--%3E%20Findings%5B(findings.jsonl)%5D%0A%20%20Audit%20-.parallel.-%3E%20Drift%5Bauditor-vocab-drift%5D%0A%20%20Drift%20--%3E%20Advisories%5B(vocab-advisories.jsonl)%5D%0A%20%20Findings%20--%3E%20Contribute%5Bauditor-contribute%5D%0A%20%20Contribute%20--%3E%20PR%5Bthird-party%20PR%5D%0A%20%20PR%20--%3E%20Track%5Bauditor-track%5D%0A%20%20Track%20--%3E%7Cmerged%20%2B%20re-audit%7C%20CaseStudy%5Bauditor-case-study%5D%0A%20%20Track%20--%3E%7Call%20clean%2C%20score%20%E2%89%A5%2090%7C%20Exemplar%5Bauditor-exemplar%5D%0A%20%20Track%20--%3E%7Cclosed%2C%20pushback%7C%20Disputed%5B(disagreements.jsonl)%5D%0A%20%20Exemplar%20--%3E%20CiteExemplars%5Bauditor-cite-exemplars%5D%0A%20%20CiteExemplars%20--%3E%7Cpositive%20warrant%20PR%7C%20Rulebook%5B(skills%2Fnlpm%2Frules)%5D%0A%20%20Findings%20--%3E%20Health%5Brule-health.py%5D%0A%20%20Disputed%20--%3E%20Health%0A%20%20Health%20--%3E%7Cnoisy%2C%20disputed%7C%20Refine%5Bauditor-refine-rules%5D%0A%20%20Refine%20--%3E%7Chuman-gated%20PR%7C%20Rulebook%0A%20%20Rulebook%20-.next%20audit.-%3E%20Discover%0A%0A%20%20classDef%20auto%20fill%3A%23d5e0ff%2Cstroke%3A%232b5fff%2Ccolor%3A%231d2433%0A%20%20classDef%20data%20fill%3A%23fff%2Cstroke%3A%23444%2Ccolor%3A%23333%0A%20%20classDef%20gate%20fill%3A%23fffbf0%2Cstroke%3A%23c47c00%2Ccolor%3A%231d2433%0A%20%20class%20Discover%2CAudit%2CDrift%2CContribute%2CTrack%2CCaseStudy%2CExemplar%2CHealth%20auto%0A%20%20class%20Findings%2CAdvisories%2CDisputed%2CRulebook%20data%0A%20%20class%20CiteExemplars%2CRefine%20gate%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=a('<p>Everything before <code>auditor-refine-rules</code> and <code>auditor-cite-exemplars</code> is automated observation. Only those two steps mutate the rulebook, and both do it by opening a PR — never by merging. The human reviewer (xiaolai) accepts the sound proposals and closes the unsound ones. That single human-gated step is what stops the loop from amplifying its own noise.</p><h2 id="the-eighteen-workflows" tabindex="-1">The eighteen workflows <a class="header-anchor" href="#the-eighteen-workflows" aria-label="Permalink to &quot;The eighteen workflows&quot;">​</a></h2><p><code>.github/workflows/auditor-*.yml</code> — every one of them is markdown + shell + Python. No proprietary runners; no LLM agent does anything without a workflow on record.</p><table tabindex="0"><thead><tr><th>Workflow</th><th>Trigger</th><th>Role in the loop</th></tr></thead><tbody><tr><td><strong>auditor-discover</strong></td><td>Weekly cron</td><td>Find Claude Code plugin repos with ≥500 stars and ≥5 NL artifacts. Writes candidate rows to <code>auditor/registry/repos.json</code>.</td></tr><tr><td><strong>auditor-batch-processor</strong></td><td>Every 6h cron</td><td>Pick the next batch of candidates; promote them through audit → contribute → re-audit phases.</td></tr><tr><td><strong>auditor-audit</strong></td><td>Issue label <code>audit-ready</code></td><td>Security scan + NL quality audit; emits <code>findings.jsonl</code> per finding with deterministic fingerprints.</td></tr><tr><td><strong>auditor-vocab-drift</strong></td><td>Same trigger as audit, runs in parallel</td><td>Registry-free vocabulary drift advisory. Output never PR-eligible — advisory only.</td></tr><tr><td><strong>auditor-contribute</strong></td><td>Issue label <code>contribute-approved</code></td><td>Opens PRs for confidence-high findings only; respects target&#39;s CONTRIBUTING.md and CoC; stamps every PR body with <code>nlpm-metadata</code>.</td></tr><tr><td><strong>auditor-track</strong></td><td>Every 4h cron</td><td>Polls PR state, emits <code>finding_outcome</code> events on merge/close, snapshots maintainer comments.</td></tr><tr><td><strong>auditor-case-study</strong></td><td>Issue label <code>case-study-ready</code></td><td>Re-audits the target at HEAD after merge. Emits <code>finding_verified</code> events (effect-level precision) and writes the case-study article.</td></tr><tr><td><strong>auditor-exemplar</strong></td><td>Issue label <code>case-study-clean</code> (score ≥ 90, security CLEAR)</td><td>Writes a teaching artifact from a high-scoring audit; cited from the rulebook as positive real-world evidence.</td></tr><tr><td><strong>auditor-cite-exemplars</strong></td><td>Weekly cron</td><td><strong>Human-gated</strong>. Proposes <code>&gt; Real-world example:</code> lines in <code>skills/nlpm/rules/SKILL.md</code> for rules with ≥1 exemplar. Opens a PR; deterministic, no LLM.</td></tr><tr><td><strong>auditor-suppressions</strong></td><td>Weekly cron</td><td>Scans public repos for NLPM rule-override configs; surfaces which rules adopters are turning off.</td></tr><tr><td><strong>auditor-classify</strong></td><td>Daily cron</td><td>Haiku classifies snapshot maintainer comments → <code>maintainer_rejected</code> events.</td></tr><tr><td><strong>auditor-daily-report</strong></td><td>Daily cron</td><td>Pipeline state report + per-rule health classification.</td></tr><tr><td><strong>auditor-render-dashboard</strong></td><td>Daily cron</td><td>Renders the cross-repo HTML dashboard from the global logs + registry.</td></tr><tr><td><strong>auditor-repo-report</strong></td><td>Manual dispatch</td><td>Backfills per-repo HTML reports. Auto-fires at the tail of audit + vocab-drift.</td></tr><tr><td><strong>auditor-rule-review</strong></td><td>Manual dispatch</td><td>Per-rule audit: hits, verified, disputed, dormant. Used during rulebook drift investigations.</td></tr><tr><td><strong>auditor-docs-diff</strong></td><td>Daily cron</td><td>Diffs Anthropic&#39;s plugins-reference docs against NLPM&#39;s cached snapshot — surfaces spec drift before it becomes rule drift.</td></tr><tr><td><strong>auditor-integration-test</strong></td><td>Manual dispatch</td><td>End-to-end smoke test that the full pipeline still wires up.</td></tr><tr><td><strong>auditor-refine-rules</strong></td><td>Weekly cron / manual</td><td><strong>Human-gated</strong>. Runs the rule-health query, picks noisy/disputed rules, opens a refinement PR. Reviewer evaluates; never auto-merges.</td></tr></tbody></table><p>The two human-gated workflows (<code>auditor-refine-rules</code>, <code>auditor-cite-exemplars</code>) are the only steps allowed to touch the rulebook. Everything else writes to append-only logs that the gated steps read.</p><h2 id="the-data-layer" tabindex="-1">The data layer <a class="header-anchor" href="#the-data-layer" aria-label="Permalink to &quot;The data layer&quot;">​</a></h2><p>Five files carry the entire memory of the loop. They live under <code>auditor/</code> and are documented schema-by-schema in <a href="https://github.com/xiaolai/nlpm/blob/main/auditor/SCHEMAS.md" target="_blank" rel="noreferrer"><code>auditor/SCHEMAS.md</code></a>.</p><table tabindex="0"><thead><tr><th>File</th><th>Append-only</th><th>What&#39;s in it</th></tr></thead><tbody><tr><td><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/findings.jsonl" target="_blank" rel="noreferrer"><code>auditor/findings.jsonl</code></a></td><td>yes</td><td>One record per audit finding (bug, quality, security, cross-component). Each record carries a deterministic <code>fingerprint</code> (sha256 of <code>repo + rule_id + file + line + pattern</code>) that joins it across the whole pipeline.</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/disagreements.jsonl" target="_blank" rel="noreferrer"><code>auditor/disagreements.jsonl</code></a></td><td>yes</td><td>Evidence that a finding was wrong, contested, or unwelcome. Four kinds: <code>self_false_positive</code>, <code>pr_comments_snapshot</code>, <code>maintainer_rejected</code>, <code>downstream_suppression</code>.</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/logs/events.jsonl" target="_blank" rel="noreferrer"><code>auditor/logs/events.jsonl</code></a></td><td>yes</td><td>Lifecycle events from every workflow run + the aggregated outcome events (<code>finding_outcome</code>, <code>finding_verified</code>, <code>finding_introduced</code>, <code>findings_aggregated</code>).</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/vocab-advisories.jsonl" target="_blank" rel="noreferrer"><code>auditor/vocab-advisories.jsonl</code></a></td><td>yes</td><td>One record per vocabulary drift cluster. Advisory only — never reaches the contribute step.</td></tr><tr><td><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/registry/repos.json" target="_blank" rel="noreferrer"><code>auditor/registry/repos.json</code></a></td><td>mutated in place</td><td>The tracking database: repo state, scores, PRs opened, lifecycle status.</td></tr></tbody></table><p>Append-only means: fixing a record means appending a superseding event (<code>finding_amended</code>, <code>gate_override</code>), not editing the original. The audit trail is intact even for findings the system later retracted.</p><h3 id="the-fingerprint-is-the-join-key" tabindex="-1">The fingerprint is the join key <a class="header-anchor" href="#the-fingerprint-is-the-join-key" aria-label="Permalink to &quot;The fingerprint is the join key&quot;">​</a></h3><p>Every finding gets a deterministic fingerprint at creation time (<code>compute-fingerprint.sh</code> is shared by audit + contribute + re-audit). The same finding seen in a different audit run produces the same fingerprint, so the loop can answer questions like:</p><ul><li>&quot;How many times has this finding been seen across the corpus?&quot;</li><li>&quot;After we contributed the fix, did the re-audit at HEAD still find it?&quot;</li><li>&quot;Did the maintainer push back on this exact finding, or on a different one in the same PR?&quot;</li></ul>',12)),(i(),r(n,null,{default:t(()=>[d(o,{id:"mermaid-356",class:"mermaid-diagram",graph:"sequenceDiagram%0A%20%20participant%20Audit%20as%20auditor-audit%0A%20%20participant%20FP%20as%20compute-fingerprint.sh%0A%20%20participant%20Findings%20as%20findings.jsonl%0A%20%20participant%20Contribute%20as%20auditor-contribute%0A%20%20participant%20Track%20as%20auditor-track%0A%20%20participant%20ReAudit%20as%20auditor-case-study%3Cbr%2F%3E(re-audit%20at%20HEAD)%0A%20%20participant%20Events%20as%20logs%2Fevents.jsonl%0A%0A%20%20Audit-%3E%3EFP%3A%20repo%20%2B%20rule_id%20%2B%20file%20%2B%20line%20%2B%20pattern%0A%20%20FP--%3E%3EAudit%3A%20sha256%3Aa3f9c2b1...%0A%20%20Audit-%3E%3EFindings%3A%20append%20finding%20with%20fingerprint%0A%20%20Findings-%3E%3EContribute%3A%20read%20confidence%3Ahigh%0A%20%20Contribute-%3E%3ETrack%3A%20PR%20opened%20with%20fingerprint%20in%20body%0A%20%20Track-%3E%3EEvents%3A%20finding_outcome%20(merged%2Fclosed)%0A%20%20Track-%3E%3EReAudit%3A%20PR%20merged%20%E2%86%92%20trigger%20re-audit%0A%20%20ReAudit-%3E%3EFP%3A%20same%20inputs%20%E2%86%92%20same%20fingerprint%0A%20%20ReAudit-%3E%3EEvents%3A%20finding_verified%20(fixed%2Fpersists)%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=a('<p>Without the fingerprint, you can&#39;t separate &quot;the rule is bad&quot; from &quot;the rule is good but the maintainer disagrees&quot; from &quot;the rule fired in two different ways across the corpus.&quot;</p><h2 id="rule-health-—-how-the-classification-works" tabindex="-1">Rule health — how the classification works <a class="header-anchor" href="#rule-health-—-how-the-classification-works" aria-label="Permalink to &quot;Rule health — how the classification works&quot;">​</a></h2><p><a href="https://github.com/xiaolai/nlpm/blob/main/auditor/scripts/rule-health.py" target="_blank" rel="noreferrer"><code>auditor/scripts/rule-health.py</code></a> joins the four logs and classifies every rule_id into one of four buckets:</p><table tabindex="0"><thead><tr><th>State</th><th>Definition</th></tr></thead><tbody><tr><td><strong>healthy</strong></td><td>Cited often enough; merged-PR rate above threshold; verified_fixed rate (re-audit confirms fix) above threshold</td></tr><tr><td><strong>noisy</strong></td><td>High hit rate, low merged rate. Either the rule is firing on false positives, or maintainers consistently judge it not worth fixing</td></tr><tr><td><strong>disputed</strong></td><td>Hit at least three times with <code>maintainer_rejected</code> events outweighing <code>finding_verified</code> events. The rule may be defensible but is provoking enough pushback that the wording or scope needs refinement</td></tr><tr><td><strong>dormant</strong></td><td>In the catalog but zero hits in the corpus. Either the rule is irrelevant, or the discovery filter never sees the artifacts that would trigger it</td></tr></tbody></table><p>The verified signal (<code>finding_verified</code> events from the re-audit at target HEAD) is weighted above the merged signal whenever at least three findings have been verified. &quot;Maintainer accepted our PR&quot; is useful; &quot;scanner confirms the rule&#39;s target is actually gone from the code&quot; is stronger.</p><p>Per-rule output includes:</p><ul><li>hits (total findings emitted)</li><li>contributed / merged / closed_unmerged / open (PR funnel)</li><li>self_fp (we self-flagged as false positive)</li><li>maintainer_rejected (classifier output, from snapshot comments)</li><li>downstream_suppressions (rule-override entries in adopter configs)</li><li>verified_fixed / verified_persists / verify_rate</li><li>dissent_types (the categories of pushback)</li></ul>',7)),(i(),r(n,null,{default:t(()=>[d(o,{id:"mermaid-455",class:"mermaid-diagram",graph:"stateDiagram-v2%0A%20%20%5B*%5D%20--%3E%20dormant%3A%20rule%20added%20to%20catalog%0A%20%20dormant%20--%3E%20healthy%3A%20hits%20%E2%89%A5%203%2C%20merged%20rate%20OK%2C%20verified_fixed%20OK%0A%20%20healthy%20--%3E%20noisy%3A%20merged%20rate%20drops%2C%20hit%20rate%20stays%20high%0A%20%20healthy%20--%3E%20disputed%3A%20maintainer_rejected%20%E2%89%A5%203%0A%20%20noisy%20--%3E%20healthy%3A%20refinement%20merged%2C%20signal%20recovers%0A%20%20disputed%20--%3E%20healthy%3A%20refinement%20clarifies%20scope%0A%20%20noisy%20--%3E%20%5B*%5D%3A%20rule%20removed%0A%20%20disputed%20--%3E%20%5B*%5D%3A%20rule%20removed%0A%20%20dormant%20--%3E%20%5B*%5D%3A%20rule%20removed%20(never%20matched)%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[s(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=a('<p>This is what <code>auditor-refine-rules</code> consumes when it opens its weekly PR.</p><h2 id="how-rule-changes-happen" tabindex="-1">How rule changes happen <a class="header-anchor" href="#how-rule-changes-happen" aria-label="Permalink to &quot;How rule changes happen&quot;">​</a></h2><p>Two pathways. Both end at a PR; neither auto-merges.</p><h3 id="path-a-—-refinement-negative-signal" tabindex="-1">Path A — Refinement (negative signal) <a class="header-anchor" href="#path-a-—-refinement-negative-signal" aria-label="Permalink to &quot;Path A — Refinement (negative signal)&quot;">​</a></h3><p>Weekly Sunday at 09:00 UTC, <code>auditor-refine-rules</code> fires:</p><ol><li>Run <code>rule-health.py</code> over the full log set.</li><li>Filter to rules classified <code>noisy</code> or <code>disputed</code>.</li><li>For each, gather the specific findings + dissent + suppressions as evidence.</li><li>Draft proposed edits to <code>skills/nlpm/rules/SKILL.md</code> — usually tightening the rule&#39;s scope, demoting severity, or splitting one rule into two more precise rules.</li><li>Open a PR labeled <code>rule-refinement-proposal</code> against <code>main</code>.</li><li>The reviewer (xiaolai) evaluates against the evidence link in the PR body. Sound proposals merge; unsound ones close.</li></ol><p>If a <code>rule-refinement-proposal</code> PR is already open, the next run is a no-op — avoids stacking competing proposals.</p><h3 id="path-b-—-citation-positive-signal" tabindex="-1">Path B — Citation (positive signal) <a class="header-anchor" href="#path-b-—-citation-positive-signal" aria-label="Permalink to &quot;Path B — Citation (positive signal)&quot;">​</a></h3><p>Same cadence, different trigger. Weekly, <code>auditor-cite-exemplars</code> walks <code>auditor/exemplars/</code> and proposes citation lines for each rule that has at least one exemplar:</p><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ &gt; **Real-world example**: see</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ &gt; [`2389-research/review-squad`](https://github.com/2389-research/review-squad)</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ &gt; scoring 96/100 with this rule firing 0 times in the audit.</span></span></code></pre></div><p>Opens a PR labeled <code>exemplar-citation-proposal</code>. Deterministic — no LLM. The PR is small and easy to review; positive warrant is cheaper to verify than negative warrant.</p><h2 id="what-the-commit-log-shows" tabindex="-1">What the commit log shows <a class="header-anchor" href="#what-the-commit-log-shows" aria-label="Permalink to &quot;What the commit log shows&quot;">​</a></h2><p>The two paths are visible in the version history. A representative selection from the last six weeks:</p><table tabindex="0"><thead><tr><th>Commit</th><th>What changed</th><th>Why (which path)</th></tr></thead><tbody><tr><td><code>v0.7.15</code></td><td>Tightened <code>BUG-missing-frontmatter</code> scope; pre-filtered security FPs</td><td>Path A — auditor was flagging benign cases as critical</td></tr><tr><td><code>v0.7.20</code></td><td>Fixed append-only log race + classifier prompt; backfilled 1,737 findings</td><td>Pipeline data-integrity — append-only contract restored</td></tr><tr><td><code>v0.7.22</code></td><td>Cleared 3 of 4 noisy rules — <code>CC-stale-count</code>, demoted <code>SEC-unpinned-semver</code></td><td>Path A — rule-health classified them as noisy after maintainer pushback</td></tr><tr><td><code>v0.7.24</code></td><td>Rebased scoring on the agent-skills.io open standard</td><td>External spec drift — Anthropic&#39;s name-on-commands optionality contradicted an in-house assumption</td></tr><tr><td><code>v0.7.30</code></td><td>Cited <code>code.claude.com/docs</code> as primary source for the name-on-commands rule</td><td>Repeat regression — pinned to the canonical doc, not derived knowledge</td></tr><tr><td><code>v0.7.31</code></td><td>4-layer system to keep NLPM in sync with Claude Code docs</td><td>Stop the spec-drift class entirely; introduced <code>auditor-docs-diff</code></td></tr><tr><td><code>v0.7.34</code></td><td>Scorer marks manifest-vs-disk diffs as <code>confidence: high</code></td><td>Path A signal — these are deterministic, never speculative</td></tr><tr><td><code>v0.8.0</code></td><td>Standalone <code>bin/nlpm-check</code> binary + author-side templates</td><td>Audit research showed pre-commit gates were what authors needed</td></tr><tr><td><code>v0.8.17</code></td><td>Exemplar pipeline — clean high-scoring audits become teaching artifacts</td><td>Path B introduced — positive warrant, not just negative findings</td></tr><tr><td><code>v0.8.18</code></td><td>Exemplar gallery + rule-citation auto-PR</td><td>Path B operationalized</td></tr><tr><td><code>v0.8.22</code></td><td>Skip top-level <code>templates/</code> directory during scan</td><td>Tightening discovery filter; author-facing templates kept getting scored as if they were live artifacts</td></tr><tr><td><code>v1.1.2</code></td><td>Unified <code>bin/nlpm-check</code> onto the plugin version line (was <code>0.8.22</code>)</td><td>The public &quot;Validated by NLPM&quot; badge showed the checker&#39;s own <code>0.x</code> version next to a <code>v1.1.x</code> plugin; one shared version is clearer. Tool and plugin now bump together</td></tr></tbody></table><p>None of these were ideas at the start of the project. Each is a response to evidence the auditor produced.</p><h2 id="what-this-prevents" tabindex="-1">What this prevents <a class="header-anchor" href="#what-this-prevents" aria-label="Permalink to &quot;What this prevents&quot;">​</a></h2><p>The shape of the loop is designed against three specific failure modes:</p><h3 id="_1-rule-rot" tabindex="-1">1. Rule rot <a class="header-anchor" href="#_1-rule-rot" aria-label="Permalink to &quot;1. Rule rot&quot;">​</a></h3><p>Without a re-audit step, rules accumulate as long as someone is willing to add them. The corpus eventually grows past what any human can hold in head, and the rulebook drifts away from what the corpus actually contains.</p><p><code>auditor-case-study</code>&#39;s re-audit at HEAD, combined with the <code>finding_verified</code> signal, gives effect-level precision per rule. A rule that consistently produces <code>finding_verified == false</code> events isn&#39;t pulling its weight and gets refined or removed.</p><h3 id="_2-false-positive-amplification" tabindex="-1">2. False-positive amplification <a class="header-anchor" href="#_2-false-positive-amplification" aria-label="Permalink to &quot;2. False-positive amplification&quot;">​</a></h3><p>If a rule produces noise and the noise is the cheapest source of &quot;new findings,&quot; it will dominate the output. The pipeline would then optimize for false positives — every batch processed would add more noise findings to the log, which a naive learning loop would interpret as the rule &quot;being important.&quot;</p><p>The fix is two-sided. First, <code>maintainer_rejected</code> events (classifier output from <code>pr_comments_snapshot</code>) explicitly subtract from a rule&#39;s perceived value. Second, <code>downstream_suppressions</code> (adopters&#39; rule-override configs) act as a tertiary signal — if multiple unrelated projects suppress the same rule, the rule is probably wrong, not the projects.</p><h3 id="_3-autonomous-rulebook-drift" tabindex="-1">3. Autonomous rulebook drift <a class="header-anchor" href="#_3-autonomous-rulebook-drift" aria-label="Permalink to &quot;3. Autonomous rulebook drift&quot;">​</a></h3><p>The most dangerous failure mode for a self-evolving system is self-amplification: the system measures something, decides a rule needs to change based on that measurement, and merges the change without external review. After a few cycles the rulebook is optimizing for whatever signal the loop is best at producing, which may have nothing to do with what users want.</p><p>The fix is the human-gated PR. <code>auditor-refine-rules</code> and <code>auditor-cite-exemplars</code> are the only steps allowed to mutate the rulebook. Neither merges. The reviewer sees the proposed change alongside the linked evidence and accepts or rejects on judgment.</p><p>The trade-off is real — rule changes happen on a weekly cadence, not in real time. That&#39;s the cost of preventing the runaway path. Given the choice between &quot;rules update quickly&quot; and &quot;rules update correctly,&quot; NLPM picks the second. Quickly can be reapplied later; correctly can&#39;t be undone after the corpus has been re-audited against bad rules.</p><h2 id="the-shape-of-the-asset" tabindex="-1">The shape of the asset <a class="header-anchor" href="#the-shape-of-the-asset" aria-label="Permalink to &quot;The shape of the asset&quot;">​</a></h2><p>After 1,287 commits, what NLPM has accumulated is less the rulebook and more the <strong>infrastructure that keeps the rulebook honest</strong>:</p><ul><li>210 audits with structured findings and per-line evidence</li><li>28 case studies with merged PRs cited back into the rules</li><li>62 exemplars cited from the rulebook as positive warrant</li><li>18 workflows that run continuously, mutate nothing without review, and leave an append-only audit trail</li><li>Two human-gated PR paths (refinement + citation) that absorb the evidence into the only file the loop is allowed to change</li></ul><p>The rulebook itself is replaceable. The infrastructure isn&#39;t.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/_pr/530/why">Why NLPM is built</a> — the original gap and the wager</li><li><a href="/_pr/530/how-to-use-it">How to use it</a> — the commands and the standalone binaries</li><li><a href="/_pr/530/how-it-works">How it works</a> — the two pipelines and one rulebook</li><li><a href="/_pr/530/reference/">Reference</a> — R01–R51, P1–P6, scoring, vocabulary, drift</li><li><a href="/_pr/530/dashboard">Dashboard</a> — the cross-repo audit data that drives the loop</li></ul>',33))])}const k=l(u,[["render",p]]);export{w as __pageData,k as default};
